## 2️⃣  The pybind11 binding

```cpp
// file: pcapng_bindings.cpp (continued)
// ------------------------------------------------------------
#include <pybind11/pybind11.h>
#include <pybind11/stl.h>          // for std::vector<uint8_t> → Python bytes
#include <pybind11/functional.h>   // for std::function<...>
namespace py = pybind11;

// Helper: convert a Frame -> Python dict (you could also expose a custom class)
py::dict frame_to_py(const libpcapng::Frame& f) {
    py::dict d;
    d["timestamp_ns"] = f.timestamp_ns;
    d["data"]         = py::bytes(reinterpret_cast<const char*>(f.data.data()), f.data.size());
    d["hex"]          = f.to_hex();
    return d;
}

// ------------------------------------------------------------
// 3️⃣  The binding module
PYBIND11_MODULE(pcapng, m) {
    m.doc() = "Python bindings for a libpcapng‑style frame iterator";

    // ----- expose Frame as a simple immutable Python object -----
    py::class_<libpcapng::Frame>(m, "Frame")
        .def_readonly("timestamp_ns", &libpcapng::Frame::timestamp_ns)
        .def_property_readonly(
            "data",
            [](const libpcapng::Frame& f) {
                // Return a Python bytes object (copy)
                return py::bytes(reinterpret_cast<const char*>(f.data.data()), f.data.size());
            })
        .def_property_readonly("hex", &libpcapng::Frame::to_hex)
        .def("__repr__", [](const libpcapng::Frame& f) {
            std::ostringstream oss;
            oss << "<Frame ts=" << f.timestamp_ns << " len=" << f.data.size() << ">";
            return oss.str();
        });

    // ----- expose Reader (the collection) -----
    py::class_<libpcapng::Reader,
               std::shared_ptr<libpcapng::Reader>>(m, "Reader")
        .def(py::init<const std::string&>(),
             py::arg("filename"),
             "Open a pcapng file (or any text file in the mock format).")
        // ----- iterator protocol -----
        .def("__iter__", [](std::shared_ptr<libpcapng::Reader> self) {
            // Return a Python iterator that yields Frame objects.
            // We wrap the C++ iterator in a generator so that the GIL is released
            // while the underlying C++ iterator does its work.
            return py::make_iterator(
                self->begin(),
                self->end(),
                // optional *copy* policy: each yielded Frame is a copy
                py::return_value_policy::copy);
        }, py::keep_alive<0, 1>() /* keep Reader alive while iterator lives */)

        // ----- for_each(callback) convenience method -----
        .def("for_each",
             [](std::shared_ptr<libpcapng::Reader> self, py::function callback) {
                 // Release the GIL while we iterate in C++.
                 // The callback itself will reacquire the GIL each time it is called.
                 py::gil_scoped_release release;
                 for (auto it = self->begin(); it != self->end(); ++it) {
                     // Re‑acquire GIL only for the Python call.
                     py::gil_scoped_acquire acquire;
                     // Convert the Frame to a Python object (copy)
                     py::object py_frame = py::cast(*it, py::return_value_policy::copy);
                     // Call the user supplied function.  Any Python exception
                     // propagates back to the caller and aborts the walk.
                     callback(py_frame);
                 }
             },
             py::arg("callback"),
             "Iterate over all frames and invoke ``callback(frame)`` for each one.\n"
             "The callback receives a ``Frame`` object (as defined above).\n"
             "Exceptions raised in the callback abort iteration and are re‑raised.")
        ;
}
```

### Build instructions

Assuming you have **pybind11** installed (e.g. via `pip install pybind11` or your system packages) and a C++17‑compatible compiler:

```bash
# 1️⃣  Create a build directory
mkdir -p build && cd build

# 2️⃣  Compile the module (adjust Python include/library paths if needed)
c++ -O3 -Wall -shared -std=c++17 -fPIC \
    $(python3 -m pybind11 --includes) \
    ../pcapng_bindings.cpp \
    -o pcapng$(python3-config --extension-suffix)
```

You will now have a file like `pcapng.cpython-311-x86_64-linux-gnu.so` in `build/`.  
Copy (or symlink) it into your Python project, or add the `build` directory to `PYTHONPATH`.

